noncompliant:
resource firewallPolicy 'Microsoft.Network/firewallPolicies@2022-07-01' = {
  name: 'example'
  properties: {
    insights: {
      isEnabled: true
      retentionDays: 7 // Sensitive: too short
    }
  }
}

compliant:
resource firewallPolicy 'Microsoft.Network/firewallPolicies@2022-07-01' = {
  name: 'example'
  properties: {
    insights: {
      isEnabled: true
      retentionDays: 90 // Meets compliance
    }
  }
}
